import { useState } from "react";
import { loginUser } from "../services/auth";
import {
    FaUser,
    FaLock,
    FaEye,
    FaEyeSlash,
    FaBuilding,
    FaGoogle,
    FaMicrosoft,
    FaShieldAlt,
    FaCogs,
    FaChartLine
} from "react-icons/fa";

import "./Login.css";

function Login() {

    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [rememberMe, setRememberMe] = useState(false);

    const handleLogin = async (e) => {

        e.preventDefault();
        console.log("Login button clicked");

        try {

            const response = await loginUser(
                username,
                password
            );

            localStorage.setItem(
                "token",
                response.data.access_token
            );

            window.location.href = "/dashboard";

        }
        catch (error) {

            alert(
                error.response?.data?.detail ||
                error.message
            );

        }

    };

    return (

        <div className="login-container">

            {/* LEFT PANEL */}

            <div className="left-panel">

                <FaBuilding className="logo-icon" />

                <h1>Rental Management System</h1>

                <p>
                    Smart. Secure. Powerful.
                    Manage your properties with ease.
                </p>

                <div className="feature-list">

                    <div>
                        <FaShieldAlt /> Secure & Reliable
                    </div>

                    <div>
                        <FaCogs /> Smart & Simple
                    </div>

                    <div>
                        <FaChartLine /> Powerful & Scalable
                    </div>

                </div>

            </div>


            {/* RIGHT PANEL */}

            <div className="right-panel"></div>

                <div className="login-card">

                    <h2>Welcome Back! 👋</h2>

                    <p>Please sign in to your account</p>

                    <form onSubmit={handleLogin}>


                        {/* USERNAME */}

                        <div className="input-box">

                            <FaUser className="icon" />

                            <input
                                type="text"
                                placeholder="Email Address"
                                value={username}
                                onChange={(e) =>
                                    setUsername(e.target.value)
                                }
                            />

                        </div>


                        {/* PASSWORD */}

                        <div className="input-box">

                            <FaLock className="icon" />

                            <input
                                type={
                                    showPassword
                                        ? "text"
                                        : "password"
                                }
                                placeholder="Password"
                                value={password}
                                onChange={(e) =>
                                    setPassword(e.target.value)
                                }
                            />

                            <div
                                className="eye-icon"
                                onClick={() =>
                                    setShowPassword(
                                        !showPassword
                                    )
                                }
                            >

                                {
                                    showPassword
                                        ? <FaEyeSlash />
                                        : <FaEye />
                                }

                            </div>

                        </div>


                        {/* REMEMBER */}

                        <div
                            style={{
                                display: "flex",
                                justifyContent: "space-between",
                                marginBottom: "25px",
                                color: "#94a3b8",
                                fontSize: "14px"
                            }}
                        >

                            <div>

                                <input
                                    type="checkbox"
                                    checked={rememberMe}
                                    onChange={(e) =>
                                        setRememberMe(
                                            e.target.checked
                                        )
                                    }
                                />

                                <span
                                    style={{
                                        marginLeft: "8px"
                                    }}
                                >
                                    Remember me
                                </span>

                            </div>

                            <div
                                style={{
                                    color: "#3b82f6",
                                    cursor: "pointer"
                                }}
                            >
                                Forgot Password?
                            </div>

                        </div>


                        {/* LOGIN BUTTON */}

                        <button
                            className="login-btn"
                        >
                            Sign In
                        </button>


                        <hr
                            style={{
                                marginTop: "30px",
                                marginBottom: "25px",
                                borderColor: "#374151"
                            }}
                        />

                        <p
                            style={{
                                textAlign: "center",
                                color: "#94a3b8"
                            }}
                        >
                            or continue with
                        </p>


                        {/* SOCIAL BUTTONS */}

                        <div
                            style={{
                                display: "flex",
                                gap: "15px",
                                marginTop: "20px"
                            }}
                        >

                            <button
                                type="button"
                                className="social-btn"
                            >

                                <FaGoogle />

                                Google

                            </button>


                            <button
                                type="button"
                                className="social-btn"
                            >

                                <FaMicrosoft />

                                Microsoft

                            </button>

                        </div>

                    </form>

                </div>

            </div>

    );

}

export default Login;
